type IcebergTable struct {
	CreatedOn                 time.Time
	Name                      string
	DatabaseName              string
	SchemaName                string
	Owner                     *string
	ExternalVolumeName        *AccountObjectIdentifier
	CatalogName               *AccountObjectIdentifier
	IcebergTableType          IcebergTableType
	CatalogTableName          *string
	CatalogNamespace          *string
	BaseLocation              *string
	CanWriteMetadata          bool
	Comment                   *string
	NameMapping               *string
	OwnerRoleType             string
	CatalogSyncName           string
	AutoRefreshStatus         string
	PartitionSpecs            string
	CurrentPartitionSpecId    int
	IcebergTableFormatVersion int
}

func (v *IcebergTable) ID() SchemaObjectIdentifier {
	return NewSchemaObjectIdentifier(v.DatabaseName, v.SchemaName, v.Name)
}

func (v *IcebergTable) ObjectType() ObjectType {
	return ObjectTypeIcebergTable
}

